external_knowledge:
'Successful applications' here refers to those with the status 'Approved'.;
The 'fee structures' include both the current and requested fee amounts.;
'Fee type' refers to the category of the fee such as 'Application' or 'Appeal'.;

sql:
SELECT description, annual_revenue
FROM fees
WHERE fee_type = 1;

SELECT fund_name, budget
FROM funds
ORDER BY budget DESC;

SELECT DISTINCT u.user_name, u.role
FROM users u
INNER JOIN applications a ON u.user_id = a.reviewed_by;

external_knowledge:
- 'substantial annual income' refers to annual revenue greater than 10,000; 
- 'green light' implies the application status is 'approved';
- 'city planners' refers to users in the 'Planning' department.

sql:
SELECT f.description, u.user_name
FROM fees f
INNER JOIN users u ON f.modified_by = u.user_id;

SELECT fee_type_name
FROM fee_types
WHERE fee_type_id = 1;
